use postgres::{Client, NoTls, Error};

#[derive(Debug)]
pub struct User {
    pub id: i32,
    pub email: String,
    pub name: String,
}

pub fn search_users_by_email(client: &mut Client, email: &str) -> Result<Vec<User>, Error> {
    let rows = client.query(
        "SELECT id, email, name FROM users WHERE email = $1",
        &[&email],
    )?;

    let mut users = Vec::new();
    for row in rows {
        let user = User {
            id: row.get("id"),
            email: row.get("email"),
            name: row.get("name"),
        };
        users.push(user);
    }

    Ok(users)
}

pub fn search_users_by_email_pattern(client: &mut Client, email_pattern: &str) -> Result<Vec<User>, Error> {
    let rows = client.query(
        "SELECT id, email, name FROM users WHERE email ILIKE $1",
        &[&email_pattern],
    )?;

    let mut users = Vec::new();
    for row in rows {
        let user = User {
            id: row.get("id"),
            email: row.get("email"),
            name: row.get("name"),
        };
        users.push(user);
    }

    Ok(users)
}

